        content = f.read()

    lines = content.split('\n')
    basename = filepath.split('/')[-1]

    # Extract header info
    dtype = None
    dist_inner = None

    for line in lines:
        if 'Input dtype:' in line:
            dtype = line.split(':')[1].strip()
        elif '# dist_outer=' in line:
            match = re.search(r'dist_inner=(\d+)', line)
            if match:
                dist_inner = int(match.group(1))

    # Check config lines
    for line in lines:
        if ':' in line and not line.startswith('#'):
            try:
                idx = int(line.split(':')[0])
                config_str = line.split(':', 1)[1].strip()
                config = eval(config_str)
                L3 = config[3]
                v_inner = L3[1]

                # v_inner should not exceed current dist_inner
                if dist_inner and v_inner > dist_inner:
                    issues.append(f"{basename} cfg {idx}: v_inner={v_inner} > dist_inner={dist_inner}")

                # For i8, v_inner should be from standard tiers or divide dist_inner
                if dtype == 'i8':
                    std_tiers = {32, 64, 128, 256}
                    if v_inner not in std_tiers and dist_inner and dist_inner % v_inner != 0:
                        issues.append(f"{basename} cfg {idx}: i8 v_inner={v_inner} not in tiers and doesn't divide dist_inner={dist_inner}")
            except Exception as e:
                pass

for issue in issues:
    print(issue)
if not issues:
    print("No v_inner issues found in sampled files")
